animations.cssText:
@keyframes bounce { 
  0%, 100% { transform: translateY(-25%); animation-timing-function: cubic-bezier(0.8, 0, 1, 1); }
  50% { transform: none; animation-timing-function: cubic-bezier(0, 0, 0.2, 1); }
}

@keyframes spin-around { 
  0% { transform: translateZ(0px) rotate(0deg); }
  15%, 35% { transform: translateZ(0px) rotate(90deg); }
  65%, 85% { transform: translateZ(0px) rotate(270deg); }
  100% { transform: translateZ(0px) rotate(1turn); }
}

@keyframes star-movement-bottom { 
  0% { transform: translate(0px); opacity: 1; }
  100% { transform: translate(-100%); opacity: 0; }
}

@keyframes star-movement-top { 
  0% { transform: translate(0px); opacity: 1; }
  100% { transform: translate(100%); opacity: 0; }
}

@keyframes appear { 
  0% { opacity: 0; transform: translateY(20px); }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes slide-up-fade { 
  0% { opacity: 0; transform: translateY(0.5rem); }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes sidebar-separate { 
  0% { transform: translateX(60px); opacity: 0.6; }
  100% { transform: translateX(0px); opacity: 1; }
}

@keyframes sidebar-combine { 
  0% { transform: translateX(-60px); opacity: 0.6; }
  100% { transform: translateX(0px); opacity: 1; }
}

@keyframes copy-success { 
  0% { content: var(--tw-content); opacity: 0; }
  15% { content: var(--tw-content); opacity: 1; }
  100% { content: var(--tw-content); opacity: 0; }
}

@keyframes toast-apple-in { 
  0% { opacity: 0; transform: translateY(18px) scale(1); filter: blur(8px); }
  100% { opacity: 1; transform: translateY(0px) scale(1); filter: blur(0px); }
}

@keyframes toast-apple-out { 
  0% { opacity: 1; transform: translateY(0px) scale(1); filter: blur(0px); }
  100% { opacity: 0; transform: translateY(10px) scale(0.985); filter: blur(6px); }
}

@keyframes diff-toolbar-enter { 
  0% { opacity: 0; filter: blur(4px); transform: translateX(-50%) translateY(12px); }
  100% { opacity: 1; filter: blur(0px); transform: translateX(-50%) translateY(0px); }
}

@keyframes diff-text-enter { 
  0% { opacity: 0; filter: blur(4px); transform: translateX(-50%) translateY(calc(4px + 2rem)); }
  100% { opacity: 1; filter: blur(0px); transform: translateX(-50%) translateY(2rem); }
}

@keyframes diff-preview-enter { 
  0% { opacity: 0; transform: translateX(-12px); }
  100% { opacity: 1; transform: translateX(0px); }
}

@keyframes diff-preview-content-enter { 
  0% { opacity: 0; transform: scale(0.98); }
  100% { opacity: 1; transform: scale(1); }
}

@keyframes swipe-out-left { 
  0% { transform: var(--y) translate(var(--swipe-amount-x)); opacity: 1; }
  100% { transform: var(--y) translate(calc(var(--swipe-amount-x) - 100%)); opacity: 0; }
}

@keyframes swipe-out-right { 
  0% { transform: var(--y) translate(var(--swipe-amount-x)); opacity: 1; }
  100% { transform: var(--y) translate(calc(var(--swipe-amount-x) + 100%)); opacity: 0; }
}

@keyframes swipe-out-up { 
  0% { transform: var(--y) translateY(var(--swipe-amount-y)); opacity: 1; }
  100% { transform: var(--y) translateY(calc(var(--swipe-amount-y) - 100%)); opacity: 0; }
}

@keyframes swipe-out-down { 
  0% { transform: var(--y) translateY(var(--swipe-amount-y)); opacity: 1; }
  100% { transform: var(--y) translateY(calc(var(--swipe-amount-y) + 100%)); opacity: 0; }
}

@keyframes sonner-fade-in { 
  0% { opacity: 0; transform: scale(0.8); }
  100% { opacity: 1; transform: scale(1); }
}

@keyframes sonner-fade-out { 
  0% { opacity: 1; transform: scale(1); }
  100% { opacity: 0; transform: scale(0.8); }
}

rules.cssText:
@keyframes shine-pulse { 
  0% { content: var(--tw-content); background-position: 0px 0px; }
  50% { content: var(--tw-content); background-position: 100% 100%; }
  100% { content: var(--tw-content); background-position: 0px 0px; }
}
